from dataclasses import dataclass, field
from enum import Enum
from typing import Optional

class ReproductionStatus(str, Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    CONFIRMED = "confirmed"
    CANNOT_REPRODUCE = "cannot_reproduce"
    REQUIRES_CLARIFICATION = "requires_clarification"

@dataclass
class ReproductionAttempt:
    attempt_number: int
    tester: str
    model_version: str
    temperature: float
    prompt_used: str
    observed_output: str
    matched_reporter_description: bool
    notes: str

@dataclass
class TriageRecord:
    submission_id: str
    assigned_to: str
    status: ReproductionStatus
    attempts: list[ReproductionAttempt] = field(default_factory=list)
    clarification_sent_at: Optional[str] = None
    clarification_received_at: Optional[str] = None
    severity_assigned: Optional[str] = None
    triage_completed_at: Optional[str] = None

    def is_reproducible(self) -> bool:
        return any(a.matched_reporter_description for a in self.attempts)

    def needs_more_attempts(self) -> bool:
        return len(self.attempts) < 5 and not self.is_reproducible()

    def triage_summary(self) -> str:
        return (
            f"ID: {self.submission_id} | Status: {self.status.value} | "
            f"Attempts: {len(self.attempts)} | "
            f"Reproducible: {self.is_reproducible()} | "
            f"Severity: {self.severity_assigned or 'pending'}"
        )
